import pytest

def zip_dicts(*dicts) -> dict:
    keys = set().union(*dicts)
    return {k: [d.get(k) for d in dicts] for k in keys}

# Happy path tests
def test_zip_dicts_happy_path_overlapping_keys():
    """Test with two dicts having overlapping keys."""
    d1 = {'a': 1, 'b': 2}
    d2 = {'a': 3, 'c': 4}
    result = zip_dicts(d1, d2)
    expected = {'a': [1, 3], 'b': [2, None], 'c': [None, 4]}
    assert result == expected

def test_zip_dicts_happy_path_no_overlap():
    """Test with two dicts having no overlapping keys."""
    d1 = {'a': 1, 'b': 2}
    d2 = {'c': 3, 'd': 4}
    result = zip_dicts(d1, d2)
    expected = {'a': [1, None], 'b': [2, None], 'c': [None, 3], 'd': [None, 4]}
    assert result == expected

def test_zip_dicts_happy_path_multiple_dicts():
    """Test with three dicts."""
    d1 = {'a': 1}
    d2 = {'a': 2, 'b': 3}
    d3 = {'b': 4, 'c': 5}
    result = zip_dicts(d1, d2, d3)
    expected = {'a': [1, 2, None], 'b': [None, 3, 4], 'c': [None, None, 5]}
    assert result == expected

